class RateLimiter:
    """In-memory rate limiter tracking requests per key (IP, account, etc.)."""

    def __init__(self):
        # key -> list of timestamps
        self._requests: dict[str, list[float]] = defaultdict(list)

    def _cleanup(self, key: str, window: float):
        now = time.time()
        self._requests[key] = [
            ts for ts in self._requests[key] if now - ts < window
        ]

    def is_rate_limited(self, key: str, max_requests: int, window: float) -> bool:
        """Return True if *key* has exceeded *max_requests* in *window* seconds."""
        self._cleanup(key, window)
        if len(self._requests[key]) >= max_requests:
            return True
        self._requests[key].append(time.time())
        return False

    def remaining(self, key: str, max_requests: int, window: float) -> int:
        self._cleanup(key, window)
        return max(0, max_requests - len(self._requests[key]))


rate_limiter = RateLimiter()


def rate_limit(max_requests: int, window: int, key_func=None, scope: str = "default"):
    """Decorator that applies per-key rate limiting to a view function.

    Parameters
    ----------
    max_requests : int
        Maximum number of allowed requests inside *window*.
    window : int
        Time window in seconds.
    key_func : callable, optional
        A function ``(request) -> str`` that returns the rate-limit key.
        Defaults to the client IP address.
    scope : str
        A namespace so different endpoints don't share counters.
    """
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            if key_func is not None:
                raw_key = key_func(request)
            else:
                raw_key = _get_client_ip()

            key = f"{scope}:{raw_key}"

            if rate_limiter.is_rate_limited(key, max_requests, window):
                return jsonify({
                    "error": "Too many requests. Please try again later."
                }), 429

            response = f(*args, **kwargs)
            return response
        return wrapper
    return decorator


def _get_client_ip() -> str:
    """Best-effort client IP extraction (respects X-Forwarded-For behind a trusted proxy)."""
    forwarded = request.headers.get('X-Forwarded-For')
    if forwarded:
        return forwarded.split(',')[0].strip()
    return request.remote_addr or '127.0.0.1'


# ---------------------------------------------------------------------------
# Token store for password-reset / verification (server-side, single-use)
# ---------------------------------------------------------------------------

_reset_tokens: dict[str, dict] = {}  # token_hash -> metadata


def _hash_token(token: str) -> str:
    return hashlib.sha256(token.encode()).hexdigest()


def create_reset_token(email: str, ttl_seconds: int = 600) -> str:
    """Create a single-use, time-limited reset token tracked server-side."""
    token = secrets.token_urlsafe(48)
    token_hash = _hash_token(token)
    _reset_tokens[token_hash] = {
        "email": email.lower().strip(),
        "expires_at": datetime.utcnow() + timedelta(seconds=ttl_seconds),
        "used": False,
    }
    return token


def validate_reset_token(token: str) -> str | None:
    """Validate and consume a reset token. Returns the email or None."""
    token_hash = _hash_token(token)
    meta = _reset_tokens.get(token_hash)
    if meta is None:
        return None
    if meta["used"]:
        return None
    if datetime.utcnow() > meta["expires_at"]:
        del _reset_tokens[token_hash]
        return None
    # Mark as used (single-use)
    meta["used"] = True
    return meta["email"]


