@app.route('/api/search', methods=['GET'])
@rate_limit(max_requests=100, window=60, scope="search")
def search_products():
    """Primary product search endpoint.

    Rate-limited to 100 requests per minute per IP to protect against
    abuse during high-traffic sales events.
    """
    query = request.args.get('q', '').strip()

    if not query:
        return jsonify({
            "error": "Missing required query parameter 'q'."
        }), 400

    if len(query) > 200:
        return jsonify({
            "error": "Query too long. Maximum 200 characters."
        }), 400

    # Sanitize: Elasticsearch query_string can be dangerous; use match/multi_match instead.
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 20, type=int)
    per_page = min(per_page, 100)  # cap page size
    offset = (max(page, 1) - 1) * per_page

    search_body = {
        "from": offset,
        "size": per_page,
        "query": {
            "multi_match": {
                "query": query,
                "fields": ["name^3", "description", "category^2", "brand^2", "tags"],
                "type": "best_fields",
                "fuzziness": "AUTO",
            }
        },
        "highlight": {
            "fields": {
                "name": {},
                "description": {},
            }
        },
    }

    try:
        result = es.search(index=app.config['ELASTICSEARCH_INDEX'], body=search_body)
    except Exception as exc:
        app.logger.error("Elasticsearch query failed: %s", exc)
        return jsonify({
            "error": "Search service is temporarily unavailable. Please try again later."
        }), 503

    hits = result.get('hits', {})
    total = hits.get('total', {}).get('value', 0) if isinstance(hits.get('total'), dict) else hits.get('total', 0)

    products = []
    for hit in hits.get('hits', []):
        product = hit['_source']
        product['id'] = hit['_id']
        product['score'] = hit['_score']
        if 'highlight' in hit:
            product['highlight'] = hit['highlight']
        products.append(product)

    return jsonify({
        "query": query,
        "page": page,
        "per_page": per_page,
        "total": total,
        "results": products,
    }), 200


